/* wms-outbound-order-addressupdate-sql-oracle.xml - selectAddressUpdatePossibleYn - 주소변경 가능여부 조회*/
SELECT
	CTKEY
	,OWKEY
	,OBORDKEY
	,CASE WHEN
			SUM(CASE WHEN DLVRYPRGRSTATUSCD IN ('20', '30') THEN 1 ELSE 0 END) = 0
		THEN 'Y'
		ELSE 'N' END AS UPDATEYN
FROM TWORK_INFO_OB_HD
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND ORHDKEY = #{orhdkey}
AND EXTERNORDERKEY = #{externorderkey}
GROUP BY CTKEY, OWKEY, OBORDKEY

/* wms-outbound-order-addressupdate-sql-oracle.xml - selectOutboundHeaderListForAddressUpdate - 주소변경대상 조회*/
SELECT
	CTKEY
	,OWKEY
	,OBHDKEY
	,DLVRYPRGRSTATUSCD
FROM TWORK_INFO_OB_HD
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBORDKEY = #{obordkey}

