/* wms-outbound-order-addressupdate-sql-oracle.xml - updateHanjinDeliveryPrintResultCodeByAddressUpdate - 한진택배출력정보의 결과코드(RSLTCD) 를 'ADUPD' 로 변경*/
UPDATE TWORK_INFO_HANJIN_PR
SET RSLTCD = 'ADUPD'
	,RSLTMSG = NULL
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBORDKEY = #{obordkey}

mapper.delete:
/* wms-outbound-order-addressupdate-sql-oracle.xml - deleteHajnjinDeliverySubmissionByAddressUpdate - 한진택배접수정보 제거 BY OBHDKEY*/
DELETE FROM TWORK_INFO_HANJIN_SBM
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}

