/* wms-outbound-order-addressupdate-sql-oracle.xml - updateOutboundHeaderByAddressUpdate - 출고헤더 수정*/
UPDATE TWORK_INFO_OB_HD
SET ORDNM = #{ordprsnnm}
	,RCPPRSNNM = #{rcpprsnnm}
	,RCPPRSNTELNO = #{rcpprsntelno}
	,RCPPRSNTELNO2 = #{rcpprsntelno2}
	,RCPPRSNZIPCD = #{rcpprsnzipcd}
	,RCPPRSNADDR1 = #{rcpprsnaddr1}
	,RCPPRSNADDR2 = #{rcpprsnaddr2}
	,DLVYMSG = #{dlvymsg}
	,DLVRYCORPCD = NULL
	,WBLNO = NULL
	,DLVRYPRGRSTATUSCD = '00'
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}

/* wms-outbound-order-addressupdate-sql-oracle.xml - updateOutboundOrderHeaderByAddressUpdate - 출고주문헤더 수정*/
UPDATE TWORK_INFO_OB_ORD_HD
SET ORDNM = #{ordprsnnm}
	,RCPPRSNNM = #{rcpprsnnm}
	,RCPPRSNTELNO = #{rcpprsntelno}
	,RCPPRSNTELNO2 = #{rcpprsntelno2}
	,RCPPRSNZIPCD = #{rcpprsnzipcd}
	,RCPPRSNADDR1 = #{rcpprsnaddr1}
	,RCPPRSNADDR2 = #{rcpprsnaddr2}
	,DLVYMSG = #{dlvymsg}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBORDKEY = #{obordkey}
